func TestW3C_template(t *testing.T) {
	t.Parallel()
	w3cRunTests(t, []w3cTest{
		{Name: "template-001", StylesheetPath: "tests/decl/template/template-001.xsl", SourceContent: `<doc>
<!-- This test executed properly.!!!!-->
</doc>`, Assertions: []w3cAssertion{w3cAssertXML("<out> This test executed properly.!!!!</out>")}},
		{Name: "template-002", StylesheetPath: "tests/decl/template/template-002.xsl", SourceContent: `<doc>
<?PITarget Processing-Instruction 1 type='text/xml'?>
</doc>`, Assertions: []w3cAssertion{w3cAssertXML("<out>Processing-Instruction 1 type='text/xml'</out>")}},
		{Name: "template-003", StylesheetPath: "tests/decl/template/template-003.xsl", SourceContent: `<doc>
  <child1>This is the child number 1.</child1>
</doc>`, Assertions: []w3cAssertion{w3cAssertXML(`<out>
  This is the child number 1.
</out>`)}},
		{Name: "template-004", StylesheetPath: "tests/decl/template/template-004.xsl", SourceContent: "<doc attribute1=\"attribute1\"></doc>", Assertions: []w3cAssertion{w3cAssertXML("<out>attribute1</out>")}},
		{Name: "template-005", StylesheetPath: "tests/decl/template/template-005.xsl", SourceContent: "<doc></doc>", Assertions: []w3cAssertion{w3cAssertXML(`<out>
     First call 1
     Second call (recursing): 2
     Third call (recursing): 3</out>`)}},
		{Name: "template-006", StylesheetPath: "tests/decl/template/template-006.xsl", SourceContent: "<doc></doc>", Assertions: []w3cAssertion{w3cAssertXML("<o/>")}},
	})
}

